import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const setNode = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'full execution test',
    parameters: {
      assignments: {
        assignments: [
          {
            id: '1',
            name: 'status',
            value: 'ok',
            type: 'string'
          }
        ]
      }
    }
  }
});

export default workflow('manual-execution-test', 'Manual Execution Test')
  .add(manualTrigger)
  .to(setNode);
